var cq='',ip=document.getElementById('si'),ac=document.getElementById('ac');
ip.addEventListener('input',function(){var v=this.value.trim();if(!v||v.length<2){ac.style.display='none';return;}if(cq)return;showAC(v);});
ip.addEventListener('keydown',function(e){if(e.key==='Enter'){ac.style.display='none';doSearch();}if(e.key==='Escape')ac.style.display='none';});
